"""
Overfit oracle (volume-aware) for round 3 first-1000-tick IMC submission window.

Per-product optimal position trajectory computed by DP over the historical CSV,
with per-tick position changes capped to top-of-book volume to match realistic
execution. Day detected at runtime via first-tick HYDROGEL_PACK mid.
"""
import json
from datamodel import Order, TradingState


class Logger:
    def __init__(self): self.logs = ""; self.max_log_length = 3750
    def print(self, *o, sep=" ", end="\n"): self.logs += sep.join(map(str,o)) + end
    def flush(self, state, orders, conv, td):
        base = len(self.to_json([self.compress_state(state, ""), self.compress_orders(orders), conv, "", ""]))
        m = (self.max_log_length - base) // 2
        print(self.to_json([self.compress_state(state, self.truncate(state.traderData, m)), self.compress_orders(orders), conv, self.truncate(td, m), self.truncate(self.logs, m)]))
        self.logs = ""
    def compress_state(self, s, td):
        return [s.timestamp, td, [[l.symbol, l.product, l.denomination] for l in s.listings.values()],
                {p: [d.buy_orders, d.sell_orders] for p, d in s.order_depths.items()},
                self.compress_trades(s.own_trades), self.compress_trades(s.market_trades),
                s.position, self.compress_observations(s.observations)]
    def compress_trades(self, ts):
        return [[t.symbol, t.price, t.quantity, t.buyer, t.seller, t.timestamp] for arr in ts.values() for t in arr]
    def compress_observations(self, o):
        co = {p: [v.bidPrice, v.askPrice, v.transportFees, v.exportTariff, v.importTariff, v.sugarPrice, v.sunlightIndex] for p, v in o.conversionObservations.items()}
        return [o.plainValueObservations, co]
    def compress_orders(self, orders):
        return {s: [[o.symbol, o.price, o.quantity] for o in ol] for s, ol in orders.items()}
    def to_json(self, v):
        return json.dumps(v, cls=ProsperityEncoder, separators=(",", ":"))
    def truncate(self, v, m):
        return v if len(v) <= m else v[:m-3] + "..."

class ProsperityEncoder(json.JSONEncoder):
    def default(self, o):
        if isinstance(o, int) and abs(o) >= 2**53: return str(o)
        return super().default(o)

logger = Logger()

